ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?neighborhood WHERE {
  ?hospitals a :Hospitals .
  ?hospitals p:neighborhood ?neighborhood .
  ?hospitals p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Clinic.*$"))
} }
  component_2: { SELECT ?city WHERE {
  ?hospitals a :Hospitals .
  ?hospitals p:city ?city .
  ?hospitals p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Clinic.*$"))
} }
  full: { SELECT ?neighborhood ?city WHERE {
  ?hospitals a :Hospitals .
  ?hospitals p:neighborhood ?neighborhood .
  ?hospitals p:city ?city .
  ?hospitals p:name ?name_lk .
  FILTER(REGEX(STR(?name_lk), "^.*Clinic.*$"))
} }
}

PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?name ?neighborhood WHERE {
  ?hospitals a :Hospitals .
  ?doctors a :Doctors .
  ?doctors p:hasHospitals ?hospitals .
  ?hospitals p:name ?name .
  ?hospitals p:neighborhood ?neighborhood .
  ?doctors p:name ?name_f .
  FILTER(STR(?name_f) = STR("Dr. Jane Doe"))
} }
  component_2: { SELECT ?name ?city WHERE {
  ?hospitals a :Hospitals .
  ?doctors a :Doctors .
  ?doctors p:hasHospitals ?hospitals .
  ?hospitals p:name ?name .
  ?hospitals p:city ?city .
  ?doctors p:name ?name_f .
  FILTER(STR(?name_f) = STR("Dr. Jane Doe"))
} }
  full: { SELECT ?name ?neighborhood ?city WHERE {
  ?hospitals a :Hospitals .
  ?doctors a :Doctors .
  ?doctors p:hasHospitals ?hospitals .
  ?hospitals p:name ?name .
  ?hospitals p:neighborhood ?neighborhood .
  ?hospitals p:city ?city .
  ?doctors p:name ?name_f .
  FILTER(STR(?name_f) = STR("Dr. Jane Doe"))
} }
}
